#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10;
inline int Max(int x,int y){return y<x?x:y;}
inline int Min(int x,int y){return x<y?x:y;}
int mxl[N];
struct ST
{
	int mx[26][N],L[N];
	inline void build(int n=N-10)
	{
		L[0]=-1;rep(1,n,i)L[i]=L[i>>1]+1;
		memcpy(mx[0],mxl,sizeof(mxl));
		rep(1,L[n],i)rep(1,n-(1<<i)+1,j)
		{
			mx[i][j]=Max(mx[i-1][j],mx[i-1][j+(1<<(i-1))]);
		}
	}
	inline int qry(int l,int r)
	{
		if(l>r)return 0;int len=L[r-l+1];
		return Max(mx[len][l],mx[len][r-(1<<len)+1]);
	}
}st;
int ch[N<<1][2],len[N<<1],fa[N<<1],cnt=1,lst=1;
inline void ins(int c)
{
	int p=lst,np=lst=++cnt;
	for(;p&&!ch[p][c];p=fa[p])ch[p][c]=np;
	if(!p)fa[np]=1;
	else
	{
		int v=ch[p][c];
		if(len[v]==len[p]+1)fa[np]=v;
		else
		{
			int nv=++cnt;
			len[nv]=len[p]+1;fa[nv]=fa[v];
			memcpy(ch[nv],ch[v],sizeof(ch[v]));
			for(;p&&ch[p][c]==v;p=fa[p])ch[p][c]=nv;
			fa[v]=fa[np]=nv;
		}
	}
}
char s[N],t[N];
inline int find(int x,int y)
{
	int l=x,r=y,mid,res=y+1;
	while(l<=r)mid=(l+r)>>1,(mid-mxl[mid]+1>=x)?(r=mid-1,res=mid):(l=mid+1);
	return res;
}
inline void Query()
{
	int l=read(),r=read(),pos=find(l,r);
	printf("%d\n",Max(pos-l,st.qry(pos,r)));
}
inline void Solve()
{
	int S=0,T=0;char cc=getchar();
	while(cc^'a'&&cc^'b')cc=getchar();
	while(cc=='a'||cc=='b')s[S++]=cc,cc=getchar();
	cc=getchar();
	while(cc^'a'&&cc^'b')cc=getchar();
	while(cc=='a'||cc=='b')t[T++]=cc,cc=getchar();
	rep(0,T-1,i)ins(t[i]-'a');
//	printf("%d %d\n",ch[1][0],ch[1][1]);
	int p=1;rep(1,S,i)
	{
		int c=s[i-1]-'a';
		if(ch[p][c])p=ch[p][c],mxl[i]=mxl[i-1]+1;
		else
		{
			while(p^1&&!ch[p][c])p=fa[p];
			if(ch[p][c])mxl[i]=len[p]+1,p=ch[p][c];
		}
//		printf("qwq : %d %d\n",p,c);
	}
	st.build(S);
//	rep(1,S,i)printf("mxl: %d\n",mxl[i]);
	int Q=read();while(Q--)Query();
}
int main()
{
	Solve();
	return 0;
}
